questions.reponse:
1. `3` (number) : conversion implicite de "5" en nombre ;
2. `"52"` (string) : conversion implicite de 2 en chaîne (concaténation) ;
3. `NaN` (number) : `Number()` échoue car "123abc" n’est pas entièrement numérique ;
4. `true` (boolean) : toute chaîne non vide → true (y compris "false") ;
5. `42` (number) : opérateur unaire `+` convertit explicitement la chaîne nettoyée en nombre.

```javascript
function validerInscription(age, telephone, email) {
  let erreurs = [];
  // Conversion age
  let ageNum = Number(age);
  if (isNaN(ageNum) || !Number.isInteger(ageNum) || ageNum < 18 || ageNum > 65) {
    erreurs.push("age");
  }
  // Nettoyage telephone
  let telClean = telephone.replace(/[^\d]/g, '');
  if (telClean.length !== 9 || isNaN(Number(telClean))) {
    erreurs.push("telephone");
  }
  // Validation email simple
  if (!email.includes('@') || email.indexOf('.', email.indexOf('@')) === -1) {
    erreurs.push("email");
  }
  return {
    valide: erreurs.length === 0,
    erreurs: erreurs
  };
}
```

```javascript
function moyenneNotes(chaineNotes) {
  if (!chaineNotes || typeof chaineNotes !== 'string') return null;
  let parties = chaineNotes.split(',');
  let notesValides = [];
  for (let part of parties) {
    let note = parseFloat(part.trim());
    if (!isNaN(note)) {
      notesValides.push(note);
    }
  }
  if (notesValides.length === 0) return null;
  let somme = notesValides.reduce((acc, val) => acc + val, 0);
  let moyenne = somme / notesValides.length;
  return Math.round(moyenne * 100) / 100;
}
```

