1. `if (age = NaN)` → affectation, pas comparaison (et `NaN !== NaN`).
2. `if (age)` → `0` est falsy, donc un âge 0 sera traité comme "Âge invalide" au lieu de "Mineur".
3. `Number("")` → 0, perte de l’info "vide".
4. `Number(null)` → 0, pareil.
Version corrigée :
```javascript
function getAgeCategorie() {
  let input = prompt("Entrez votre âge");
  if (input === null || input.trim() === "") {
    alert("Âge invalide (champ vide)");
    return;
  }
  let age = Number(input);
  if (isNaN(age)) {
    alert("Veuillez entrer un nombre");
  } else if (age >= 18) {
    alert("Majeur");
  } else if (age >= 0) {
    alert("Mineur");
  } else {
    alert("Âge négatif interdit");
  }
}
